use poseidon::poseidon2::Poseidon2;

// Field equality proof: prove two fields from different credentials are equal
// without revealing the field values.
//
// Used for cross-document references, e.g.:
//   child.fatherName == parent.fullName
//
// Each side has its own commitment, salt, tag_id, and Merkle path.
// The circuit verifies both Merkle inclusions and asserts data equality.

fn main(
    // Credential A (e.g. child)
    siblings_a: [Field; 5],
    length_a: Field,
    data_a: [Field; 4],
    packed_hash_a: Field,
    commitment_a: pub Field,
    salt_a: pub Field,
    tag_id_a: pub Field,
    // Credential B (e.g. parent)
    siblings_b: [Field; 5],
    length_b: Field,
    data_b: [Field; 4],
    packed_hash_b: Field,
    commitment_b: pub Field,
    salt_b: pub Field,
    tag_id_b: pub Field,
) {
    // 1. Verify Merkle inclusion for A
    let leaf_a = Poseidon2::hash([tag_id_a, length_a, data_a[0], data_a[1], data_a[2], data_a[3], salt_a, packed_hash_a], 8);
    let leaf_index_a: u32 = tag_id_a as u32 - 1;
    let mut current_a = leaf_a;

    for level in 0..5 {
        let bit = (leaf_index_a >> level) & 1;
        let pair = if bit == 0 {
            [current_a, siblings_a[level]]
        } else {
            [siblings_a[level], current_a]
        };
        current_a = Poseidon2::hash(pair, 2);
    }

    assert(Poseidon2::hash([current_a, salt_a], 2) == commitment_a, "commitment A mismatch");

    // 2. Verify Merkle inclusion for B
    let leaf_b = Poseidon2::hash([tag_id_b, length_b, data_b[0], data_b[1], data_b[2], data_b[3], salt_b, packed_hash_b], 8);
    let leaf_index_b: u32 = tag_id_b as u32 - 1;
    let mut current_b = leaf_b;

    for level in 0..5 {
        let bit = (leaf_index_b >> level) & 1;
        let pair = if bit == 0 {
            [current_b, siblings_b[level]]
        } else {
            [siblings_b[level], current_b]
        };
        current_b = Poseidon2::hash(pair, 2);
    }

    assert(Poseidon2::hash([current_b, salt_b], 2) == commitment_b, "commitment B mismatch");

    // 3. Assert field data equality
    assert(length_a == length_b, "field lengths differ");
    assert(data_a[0] == data_b[0], "data[0] mismatch");
    assert(data_a[1] == data_b[1], "data[1] mismatch");
    assert(data_a[2] == data_b[2], "data[2] mismatch");
    assert(data_a[3] == data_b[3], "data[3] mismatch");
}

